foreach ($key in $data.Keys) {
    if (Test-Path $key) {
        $content = Get-Content $key -Raw
        
        $decoded = [System.Text.Encoding]::UTF8.GetString([Convert]::FromBase64String($data[$key]))
        
        $pattern1 = '¥|¥s*¥|¥s*¥|¥s*¥|[¥r¥n]+¥|¥s*¥|¥s*¥|¥s*¥|'
        $pattern2 = '<!-- Add your own.*-->'
        
        if ($content -match $pattern1) {
            $content = $content -replace $pattern1, $decoded
        } elseif ($content -match $pattern2) {
            $content = $content -replace $pattern2, $decoded
        } else {
            $content += "`n`n" + $decoded
        }
        
        # Make sure to write as UTF-8
        $utf8NoBom = New-Object System.Text.UTF8Encoding $false
        [System.IO.File]::WriteAllText((Resolve-Path $key).Path, $content, $utf8NoBom)
        
        Write-Host "Populated: $key"
    }
}
